class Animal:
    def speak(self):
        return 'sound'
class Dog(Animal):
    def speak(self):
        return 'bark'
print(Dog().speak())

class A:
    def greet(self):
        print('hello from A')
class B(A):
    def greet(self):
        super().greet()
B().greet()

class P:
    def __init__(self, x, y):
        self.x, self.y = x, y
    def __repr__(self):
        return f'P({self.x}, {self.y})'
print(P(1, 2))

class Foo:
    @classmethod
    def name(cls):
        return cls.__name__
print(Foo.name())

class C:
    @property
    def value(self):
        return 10
print(C().value)
